import java.util.HashSet;

class Main {
  public static void main(String[] args) {
    HashSet<String> visitors = new HashSet<String>();

    visitors.add("192.168.0.1");
    visitors.add("10.0.0.5");
    visitors.add("192.168.0.1"); // DUPLICATE! It is ignored quietly.

    // The size will only be 2, because the duplicate was rejected.
    System.out.println("Unique Visitors: " + visitors.size());
  }
}
